"""family_lsp_2: cheaper-representation rebuilds of memory-dominated incumbents.

Slice mine = golf_targets[2::7]. Each incumbent (out_p6) was inspected: its
dominant intermediates are float arithmetic pipelines (ReduceSum/MatMul/Sub/Abs/
Less/Relu over [1,10,30,30] one-hot grids), NOT pure geometry -> a label-space
single-channel rewrite is not numerically equivalent for these graphs (the MatMuls
mix spatial positions; task365's cost is a data-dependent 900x900 same-value
group-sum matrix, not a static gather). The applicable, byte-safe lever is FP16
intermediate lowering: every FLOAT32 intermediate is re-emitted as FLOAT16 (2B vs
4B). Graph I/O stays FLOAT32[1,10,30,30] via a leading Cast(input)->f16 and a
trailing Cast(f16)->output; all internal float ops + initializers are float16;
bool/int tensors keep their native dtype.

Only tasks where FP16 both (a) reproduces every train+test pair EXACTLY after the
(>0) threshold and (b) lowers the grader cost offline are embedded; the fixed
two-boundary-cast overhead makes FP16 a net loss on tiny incumbents and a
comparison-boundary precision loss on task330, so those keep the incumbent. Each
task ships the FP16 model AND the unchanged incumbent as a fallback candidate, so
the harness keeps whichever is cheaper (monotone -- never regresses). Detection is
behavioural + self-contained: every embedded model is run (onnxruntime) on the
task's pairs and proposed only when exact. OPSET-10, self-contained, IR/opset
unchanged from the incumbent.
"""
from __future__ import annotations

import base64
import gzip

import numpy as np
import onnx

try:
    import onnxruntime as _ort
except Exception:  # pragma: no cover
    _ort = None


# task -> gzip+base64 of the FP16-lowered ONNX model
_FP16 = {
    138: "",
    106: "",
    383: "",
    51: "",
    235: "",
    398: "",
}

# task -> gzip+base64 of the unchanged incumbent (fallback candidate)
_INC = {
    138: "",
    106: "",
    383: "",
    51: "",
    235: "",
    398: "",
}

_SESS = {}


def _raw(blob):
    return gzip.decompress(base64.b64decode(blob))


def _session(blob):
    s = _SESS.get(blob)
    if s is None:
        so = _ort.SessionOptions()
        so.graph_optimization_level = _ort.GraphOptimizationLevel.ORT_DISABLE_ALL
        so.log_severity_level = 3
        s = _ort.InferenceSession(_raw(blob), so)
        _SESS[blob] = s
    return s


def _onehot(grid):
    g = np.asarray(grid, dtype=np.int64)
    h, w = g.shape
    x = np.zeros((1, 10, 30, 30), dtype=np.float32)
    for r in range(h):
        row = g[r]
        for c in range(w):
            x[0, int(row[c]), r, c] = 1.0
    return x


def candidates(examples):
    if _ort is None:
        return []
    pairs = list(examples.get("train", [])) + list(examples.get("test", []))
    data = []
    for e in pairs:
        gi = np.asarray(e["input"]); go = np.asarray(e["output"])
        if gi.ndim != 2 or go.ndim != 2:
            continue
        if max(gi.shape) > 30 or max(go.shape) > 30:
            continue
        data.append((_onehot(gi), _onehot(go)))
    if not data:
        return []
    out = []
    for t in _FP16:
        blob = _FP16[t]
        try:
            sess = _session(blob)
        except Exception:
            continue
        ok = True
        for x, tg in data:
            try:
                y = sess.run(["output"], {"input": x})[0]
            except Exception:
                ok = False
                break
            if np.asarray(y).shape != tg.shape or not np.array_equal(np.asarray(y) > 0.0, tg > 0.0):
                ok = False
                break
        if not ok:
            continue
        try:
            out.append((f"lsp2_fp16_{t}", onnx.load_from_string(_raw(blob))))
        except Exception:
            pass
        inc = _INC.get(t)
        if inc is not None:
            try:
                out.append((f"lsp2_inc_{t}", onnx.load_from_string(_raw(inc))))
            except Exception:
                pass
    return out
